css:
/* ---- Cash Document Print Format ---- */
body { font-family: Arial, sans-serif; font-size: 11pt; color: #222; }
.cd-header { border-bottom: 2px solid #333; padding-bottom: 8px; margin-bottom: 16px; }
.cd-title { font-size: 16pt; font-weight: bold; }
.cd-ref { font-size: 10pt; color: #555; }
.cd-section { margin-top: 16px; margin-bottom: 4px; border-bottom: 1px solid #bbb; font-weight: bold; font-size: 10pt; text-transform: uppercase; color: #444; letter-spacing: 0.05em; }
.cd-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 4px 24px; margin-top: 6px; }
.cd-grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 4px 16px; margin-top: 6px; }
.cd-row { display: flex; gap: 6px; align-items: baseline; margin: 2px 0; }
.cd-label { font-size: 9pt; color: #666; min-width: 120px; }
.cd-value { font-size: 10pt; font-weight: 500; }
.cd-badge { display: inline-block; padding: 1px 8px; border-radius: 3px; font-size: 9pt; font-weight: bold; }
.cd-badge-final { background: #d4edda; color: #155724; }
.cd-badge-draft { background: #fff3cd; color: #856404; }
.cd-badge-open { background: #d1ecf1; color: #0c5460; }
table.cd-table { width: 100%; border-collapse: collapse; margin-top: 6px; font-size: 9.5pt; }
table.cd-table th { background: #f0f0f0; border: 1px solid #ccc; padding: 4px 8px; text-align: left; font-weight: bold; }
table.cd-table td { border: 1px solid #ddd; padding: 3px 8px; vertical-align: top; }
table.cd-table tr:nth-child(even) td { background: #fafafa; }
.cd-amounts { display: grid; grid-template-columns: 1fr 1fr; gap: 4px 24px; margin-top: 6px; }
.cd-amount-box { border: 1px solid #ddd; border-radius: 4px; padding: 6px 12px; }
.cd-amount-label { font-size: 8.5pt; color: #777; }
.cd-amount-value { font-size: 12pt; font-weight: bold; }
.cd-footer { margin-top: 24px; font-size: 8.5pt; color: #888; border-top: 1px solid #eee; padding-top: 6px; }
